{
  "name": "North Dakota Aging in Community (AIC) Project",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits defined for AIC; general ND aging programs like SPED use limits varying by household size (exact amounts not specified in sources) and sliding scale based on countable income and family size[1][5].",
    "asset_limits": "No specific asset limits for AIC; related SPED program has liquid assets under $50,000 (home value exempt)[5].",
    "other_requirements": ["North Dakota resident", "Older adults (likely 65+) wishing to age in rural homes/communities", "Reside in one of two targeted rural communities", "Commitment to community-focused solutions and engagement[2][4][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Community-based models and interventions including personal finance, connection and growth, transportation, health and wellness, housing; tailored solutions via local partnerships, assessments, and stakeholder feedback to support aging in place[2][7]. No fixed dollar amounts or hours specified.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact NDSU Extension (no specific phone/URL listed for applications; visit https://www.ndsu.edu/agriculture/extension/programs/aging-community-program for program details[7]", "Community engagement through local stakeholders in two rural communities[2]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": [],
    "documents": ["Not specified; likely community assessment feedback or proof of residency"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to two rural communities in North Dakota (specific names not identified in sources)",
    "regional_variations": "Tailored interventions based on community assessments in each of the two rural sites; focuses on local needs like housing, transportation, social isolation[2][7]",
    "offices_or_providers": ["NDSU Extension leading, with community stakeholders in two rural communities[2][7]"]
  },
  "official_source": "https://www.ndsu.edu/agriculture/extension/programs/aging-community-program[7]",
  "gotchas": ["Not a direct service entitlement program like SPED or Medicaid HCBS; it's a project developing community models, not individual applications for benefits[2][7]", "Limited to specific rural communities, not statewide[2]", "No clear individual eligibility/application process; emphasizes community partnerships over personal enrollment[7]", "People may confuse with SPED (which has payments/respite) or other HCBS programs[1][5]"],
  "data_shape_notes": "Project-based initiative in only 2 rural communities developing local aging-in-place models; no individual income/asset tests, fixed benefits, or standard application; community-tailored via NDSU Extension partnerships"
}

