{
  "name": "North Dakota State Health Insurance Assistance Program (ND SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries (typically age 65+ or under 65 with disabilities), their families, and caregivers. Supports people with limited incomes but does not impose specific dollar thresholds for SHIP services themselves[4][5].",
    "asset_limits": "No asset limits for SHIP counseling services[4][5].",
    "other_requirements": ["Medicare beneficiary (Parts A/B eligible), family member, or caregiver", "North Dakota resident (services statewide)", "US citizen or qualified noncitizen not required for counseling, but may apply for related programs like Extra Help[1][2][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, personalized one-on-one counseling and education on Medicare options (Original Medicare Parts A/B, Medicare Advantage Part C, Part D prescription drugs, Medigap); assistance applying for savings programs (Medicare Savings Program, Extra Help/Low-Income Subsidy, Medicaid); help comparing plans, understanding eligibility/enrollment, coverage coordination, appeals of denied claims, managing bills; outreach via presentations, health fairs; no sales of insurance products[2][4][5][8].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-888-575-6611", "TTY: 1-800-366-6888", "Website: North Dakota Insurance Department SHIP page (https://www.insurance.nd.gov/consumers/medicare/ship-counselors)", "In-person or local: Contact via phone for volunteer counselor appointment (approx. 45 volunteers statewide)[2][6]"],
    "processing_time": "Immediate phone counseling available; in-person appointments scheduled based on counselor availability, no formal processing[5][6].",
    "waitlist": null,
    "forms": ["No specific application form required for counseling; forms only for related programs like Extra Help or MSP applications assisted by counselors[4][5]"],
    "documents": ["Medicare card, current Medicare plan details, income/asset info if applying for savings programs (e.g., bank statements for Extra Help), prescription drug list, medical bills for appeals; not required for initial counseling[4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered by approximately 45 trained volunteers across the state; no noted differences in services, wait times, or providers by region, though local availability depends on volunteer locations[2].",
    "offices_or_providers": ["Volunteers via North Dakota Insurance Department; contact central line for local counselor[2][6]"]
  },
  "official_source": "https://www.insurance.nd.gov/consumers/medicare/ship-counselors",
  "gotchas": ["Not a financial aid or healthcare provider program—offers free counseling only, not direct payments or medical services; counselors have no conflicts of interest and do not sell plans[2][5]", "Confused with ND State Health Improvement Plan (different SHIP acronym for public health strategy)[7]", "Must be Medicare-related issue; for pure Medicaid, contact HHS separately[1]", "Volunteers may have scheduling limits in rural areas[2]"],
  "data_shape_notes": "no income/asset test for core counseling; volunteer-delivered statewide; assists with tiered savings programs (e.g., Extra Help has limits) but SHIP access is universal for Medicare beneficiaries"
}
